import{_ as o,a as r,b as n,c as a,d as i,e as d,f as s,g as l}from"./chunks/stroke_stroke_over_fill.BSl5R5js.js";import{b as h,a as c,_ as g,c as p}from"./chunks/gradient_colorspace_linear_rgb.DDCeKl0l.js";import{_ as u,a as b,b as m}from"./chunks/bounding_box.DUhxQAFs.js";import{_ as f,C as y,o as x,c as w,E as v,a2 as k}from"./chunks/framework.CkaEw-3u.js";const S="/mug-typography-docs/image/gradient_example.webp",T="/mug-typography-docs/image/gradient_crayon.webp",G=JSON.parse('{"title":"Global Settings","description":"Text-wide transform, color, stroke, shadow, and bounding-box controls","frontmatter":{"title":"Global Settings","description":"Text-wide transform, color, stroke, shadow, and bounding-box controls","pageClass":"reference-page","head":[["link",{"rel":"canonical","href":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-global-settings.html"}],["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:site_name","content":"Mug Typography Manual"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:title","content":"Global Settings | Mug Typography Manual"}],["meta",{"property":"og:description","content":"Text-wide transform, color, stroke, shadow, and bounding-box controls"}],["meta",{"property":"og:url","content":"https://mug-lab-3.github.io/mug-typography-docs/en/reference/reference-global-settings.html"}],["meta",{"property":"og:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"property":"og:image:type","content":"image/jpeg"}],["meta",{"property":"og:image:width","content":"1200"}],["meta",{"property":"og:image:height","content":"630"}],["meta",{"property":"og:image:alt","content":"Mug Typography Online Manual"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:site","content":"@MugLab3"}],["meta",{"name":"twitter:title","content":"Global Settings | Mug Typography Manual"}],["meta",{"name":"twitter:description","content":"Text-wide transform, color, stroke, shadow, and bounding-box controls"}],["meta",{"name":"twitter:image","content":"https://mug-lab-3.github.io/mug-typography-docs/image/social-card.jpg"}],["meta",{"name":"twitter:image:alt","content":"Mug Typography Online Manual"}]]},"headers":[],"relativePath":"en/reference/reference-global-settings.md","filePath":"en/reference/reference-global-settings.md"}'),O={name:"en/reference/reference-global-settings.md"};function _(B,t,C,F,P,E){const e=y("ReferenceOverview");return x(),w("div",null,[v(e,{eyebrow:"PARAMETER REFERENCE",title:"Global Settings",description:"Find the text-wide controls for typography, transforms, color, stroke, shadow, and backgrounds by purpose.",items:[{icon:"Aa",title:"Text",description:"Text, font, and typography",href:"#text-settings"},{icon:"↗",title:"Transform",description:"Position, rotation, and stretch",href:"#transform"},{icon:"◐",title:"Color",description:"Fill, transparency, and gradients",href:"#color-settings"},{icon:"◇",title:"Stroke",description:"Outline, gap, and joins",href:"#outline-stroke"},{icon:"◒",title:"Shadow",description:"Distance, angle, and color",href:"#shadow-settings"},{icon:"▣",title:"Background",description:"Borders, fills, and padding",href:"#bounding-box-settings"}]}),t[0]||(t[0]=k('<p><a id="page-global-settings"></a></p><p>This page configures Text Settings (text, font, typesetting, morph animation), the overall Transform, Color Settings (fill color and gradient), the outline (Stroke), drop shadow, and bounding box.</p><p><img src="'+o+'" alt="Global Settings (top)"></p><p><img src="'+r+'" alt="Global Settings (bottom)"></p><h2 id="reset" tabindex="-1">Reset <a class="header-anchor" href="#reset" aria-label="Permalink to &quot;Reset&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th></tr></thead><tbody><tr><td><strong>Reset All Characters</strong></td><td>Resets Pos, Pivot, Scale, Stretch, Rotation, Margin After, Use Indiv Color, Color, Use Indiv Stroke, Stroke Width, Stroke Gap, and Stroke Color for all characters and parts to their default values.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Reset only affects <strong>per-character and per-part individual settings</strong>. Global Settings (settings applied to the entire text) are not reset.</p></div><h2 id="text-settings" tabindex="-1">Text Settings <a class="header-anchor" href="#text-settings" aria-label="Permalink to &quot;Text Settings&quot;">​</a></h2><p>A group that configures the text content, font, and typesetting (alignment, spacing, and overall scale) together.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Text</strong></td><td>Enter the text to be displayed. Max character limit depends on the selected preset (see &quot;<a href="#limitations">Limitations</a>&quot; in the Appendix). For multi-line input, please refer to the note below.</td><td>-</td><td>When entering the string to display.</td></tr><tr><td><strong>Font</strong></td><td>Select the font to use from the list.</td><td>-</td><td>When you want to change the typeface.</td></tr><tr><td><strong>Horizontal Alignment</strong></td><td>Select the horizontal text alignment (Left / Center / Right).</td><td><code>Center</code></td><td>When you want to align the start/end of multiple lines of text.</td></tr><tr><td><strong>Vertical Alignment</strong></td><td>Select the vertical text alignment (Top / Center / Bottom / Baseline).<br>・<strong>Top</strong>: Aligns text relative to the top edge.<br>・<strong>Center</strong>: Aligns text relative to the center of the ink bounding box (the drawn area).<br>・<strong>Bottom</strong>: Aligns text relative to the bottom edge.<br>・<strong>Baseline</strong>: Aligns text relative to the text baseline (prevents vertical shifting when text content changes and stabilizes vertical morph animation).</td><td><code>Center</code></td><td>When you want to set the vertical reference point of the text (the effect is most visible with multi-line or vertical text).</td></tr><tr><td><strong>Vertical Mode</strong></td><td>When turned ON, text is written vertically.</td><td>OFF</td><td>When creating vertically-set Japanese titles or vertical subtitles.</td></tr><tr><td><strong>Tracking</strong></td><td>Specifies the global character spacing applied uniformly to all characters, in em units. Positive values widen spacing; negative values narrow it. This value is summed with each character&#39;s individual Margin After.</td><td><code>0.0</code></td><td>When you want to tighten or loosen the overall character spacing to adjust the look of the text.</td></tr><tr><td><strong>Line Spacing</strong></td><td>Specifies the line spacing for multi-line text, in em units (relative to font size).</td><td><code>1.0</code></td><td>When you want to adjust the gap between lines in multi-line text.</td></tr><tr><td><strong>Scale</strong></td><td>Scales the entire text uniformly.</td><td><code>1.0</code></td><td>When changing the overall size of the text at once.</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p><strong>Multi-line Text Input and Line Breaks</strong></p><ul><li><p><strong>Inputting on the Fusion Page:</strong> On the Fusion page, you can type newlines directly by pressing the Enter key to write multi-line text.</p></li><li><p><strong>Inputting on the Edit Page:</strong> Due to Edit page Inspector UI limitations, you cannot type Enter to create newlines directly in the text box. If you want to write multi-line text on the Edit page, insert <code>\\n</code> or <code>&lt;br&gt;</code> at the desired line break positions. These are automatically treated as line breaks.</p><p>Also note that on the Edit page, pressing Enter while typing may move focus to a different parameter instead of inserting a line break. Be careful not to press Enter unintentionally while typing.</p></li><li><p><strong>Escaping Line Breaks:</strong> If you want to render the literal characters <code>\\n</code> or <code>&lt;br&gt;</code> without breaking the line, prepend them with a backslash to escape them: <code>\\\\n</code> or <code>\\&lt;br&gt;</code>.</p></li></ul><table tabindex="0"><thead><tr><th>Input in the Text field</th><th>Rendered result</th></tr></thead><tbody><tr><td><code>あ\\nい</code></td><td>あ<br>い (rendered on two lines)</td></tr><tr><td><code>あ&lt;br&gt;い</code></td><td>あ<br>い (rendered on two lines)</td></tr><tr><td><code>あ\\\\nい</code></td><td>あ\\nい (escaped — no line break, shown as a single line)</td></tr><tr><td><code>あ\\&lt;br&gt;い</code></td><td>あ&lt;br&gt;い (escaped — no line break, shown as a single line)</td></tr></tbody></table></div><p><a id="morph-animation"></a></p><h3 id="morph-animation" tabindex="-1">Morph Animation <a class="header-anchor" href="#morph-animation" aria-label="Permalink to &quot;Morph Animation&quot;">​</a></h3><p>A group for morph animation, located just below the <strong>Text</strong> field in Text Settings. It smoothly morphs the outlines of the string entered in <strong>Text</strong> into the outlines of another string — for example, making &quot;A&quot; melt into &quot;B.&quot;</p><p><img src="'+n+'" alt="Morph animation example"></p><p><strong>Basic Usage:</strong></p><ol><li>Turn <strong>Enable Morph</strong> ON.</li><li>Enter the <strong>starting</strong> string in <strong>Text</strong>.</li><li>Enter the <strong>ending</strong> string in <strong>To Text</strong>.</li><li>Keyframe <strong>Progress</strong> to go from <code>0</code> (starting text) to <code>1</code> (ending text).</li></ol><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Enable Morph</strong></td><td>Enables morph animation. When ON, the normal text rendering is replaced by a morph from Text (start) to To Text (end).</td><td>OFF</td></tr><tr><td><strong>To Text</strong></td><td>Enter the destination text the morph ends at. Multi-line is supported.</td><td>(empty)</td></tr><tr><td><strong>Progress</strong></td><td>Specifies the morph progress from <code>0.0</code> (= the Text state) to <code>1.0</code> (= the To Text state). <strong>Keyframe this value on the timeline</strong> to freely control the speed and timing of the morph. Easing is also adjusted via this keyframe curve.</td><td><code>0.0</code></td></tr><tr><td><strong>Matching Strength</strong></td><td>Specifies how strongly the morph refines its part pairings beyond simple spatial proximity. At <code>0.0</code>, parts are matched based purely on position (original behaviour). Higher values do two things: (1) they consider <strong>filled-area similarity</strong>, preferring to pair parts with similar painted area (e.g., avoiding a small dot pairing with a full stroke), and (2) they keep a character that has an individual color, stroke, or shadow paired with the character at the <strong>same position</strong> in the To Text, so its individual styling is not stranded onto an unrelated glyph.</td><td><code>0.3</code></td></tr><tr><td><strong>Same Glyph Priority</strong></td><td>Specifies the strength of pairing <strong>identical characters</strong> between the start and end texts. At <code>0.0</code>, characters match purely by position. At <code>1.0</code>, identical characters are always paired regardless of distance. Identical character pairs slide into place rather than changing shape, keeping the animation clean.</td><td><code>0.3</code></td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Path Deformation effects (Pulse / Trapezoid / Sphere / Barrel) and the Hand Drawn effect can also be layered on top of the morph result.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>You can morph <strong>even when the starting and ending texts have a different number of characters</strong> (excess characters automatically appear/disappear). However, texts with a similar number of characters and similar shape complexity (part count) morph more naturally and cleanly.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If part matching does not behave as intended, try changing <strong>Horizontal Alignment</strong> from <code>Center</code> to <code>Left</code> or <code>Right</code>. This changes the relative character positions and can change the matching result. For vertical movement, try <code>Baseline</code> under <strong>Vertical Alignment</strong>.</p></div><h2 id="transform" tabindex="-1">Transform <a class="header-anchor" href="#transform" aria-label="Permalink to &quot;Transform&quot;">​</a></h2><p>A group that configures the position, rotation, and stretch applied to the entire text at once.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Position</strong></td><td>Specifies the position of the entire text on the canvas. <code>0.5, 0.5</code> is the center of the canvas.</td><td><code>0.5, 0.5</code></td><td>When positioning the text within the frame.</td></tr><tr><td><strong>Pivot</strong></td><td>Specifies the pivot point for rotation and scaling on the canvas.</td><td><code>0.5, 0.5</code></td><td>When you want to shift the rotation/scaling axis to an edge or other arbitrary position.</td></tr><tr><td><strong>Rotation</strong></td><td>The rotation angle of the entire text (in degrees).</td><td><code>0°</code></td><td>When you want to tilt the entire text.</td></tr><tr><td><strong>Stretch</strong></td><td>Scales the X and Y directions individually.</td><td><code>1.0, 1.0</code></td><td>When deliberately squashing or stretching the text vertically/horizontally for a logo-like look.</td></tr></tbody></table><p>The 3D presets also show these parameters in the Transform group.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th style="text-align:right;">Default</th></tr></thead><tbody><tr><td><strong>Global Yaw</strong></td><td>Tilts the entire text horizontally around the Global Pivot.</td><td style="text-align:right;"><code>0°</code></td></tr><tr><td><strong>Global Pitch</strong></td><td>Tilts the entire text vertically around the Global Pivot.</td><td style="text-align:right;"><code>0°</code></td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The overall uniform scaling (Scale) is located in the Text Settings group. While Scale changes both X and Y simultaneously, Stretch modifies only one axis, which is useful for distorting text vertically or horizontally.</p></div><h2 id="color-settings" tabindex="-1">Color Settings <a class="header-anchor" href="#color-settings" aria-label="Permalink to &quot;Color Settings&quot;">​</a></h2><p>A group that configures the text fill color, transparent fill, and gradient together.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th><th>Use Case</th></tr></thead><tbody><tr><td><strong>Font Color</strong></td><td>Specifies the base color (RGB + Opacity) for the entire text.</td><td>-</td><td>When you want to set the overall base color of the text. Also serves as the gradient&#39;s start color.</td></tr><tr><td><strong>Transparent Fill</strong></td><td>When turned ON, the text body (fill) is made fully transparent and only the outline (Stroke) is rendered.</td><td>OFF</td><td>When you want to create outlined (hollow) text. Use it together with a Stroke Width greater than <code>0.0</code>. Note that it does not apply to characters or parts that use an individual color (Use Indiv Color) on the Character / Part side.</td></tr></tbody></table><p><img src="'+a+'" alt="Example of hollow text using Transparent Fill"><em>(Example of hollow text created by turning Transparent Fill ON and setting the Stroke Width / Gap.)</em></p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The Edit page cannot set the alpha value (transparency) of color parameters. See &quot;<a href="/mug-typography-docs/en/reference/appendix.html#limitations">Limitations</a>&quot; in the appendix for details.</p></div><h3 id="gradient" tabindex="-1">Gradient <a class="header-anchor" href="#gradient" aria-label="Permalink to &quot;Gradient&quot;">​</a></h3><p>A subgroup within the Color Settings group. Applies a gradient to the entire text using Font Color as the start color. The gradient is enabled when Color Space is set to any value other than <code>None</code> (the only exception is <code>Crayon</code>, which draws scribble strokes instead of a gradient; see below).</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The gradient range is calculated from the <strong>bounding box (BB) encompassing all parts at their transformed positions</strong>. If any character or part is moved or scaled such that the BB changes, the gradient range shifts across all characters accordingly.</p></div><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Color Space</strong></td><td>Selects the color interpolation mode for the gradient. <code>None</code> disables the gradient. <code>Okhsv</code> / <code>Okhsl</code> provide perceptually uniform, hue-preserving interpolation. <code>Oklab</code> interpolates in perceptual lightness space. <code>Linear RGB</code> uses linear RGB interpolation. <code>Crayon</code> is a special mode that, instead of a gradient, draws hand-scribbled strokes in the end color (Gradient End Color) over the normal fill (see below).</td><td><code>None</code></td></tr><tr><td><strong>Gradient End Color</strong></td><td>The end color of the gradient (RGB + Opacity). Font Color serves as the start color.</td><td>Orange (<code>#ff8000</code>, opaque)</td></tr><tr><td><strong>Midpoint</strong></td><td>The position of the 50/50 blend point between start and end colors (0.5 = equal split).</td><td><code>0.5</code></td></tr><tr><td><strong>Angle</strong></td><td>The gradient direction in degrees. 0° is left to right, 90° is top to bottom.</td><td><code>270°</code></td></tr><tr><td><strong>Start</strong></td><td>The gradient start position relative to the bounding box (0 = BB start, 1 = BB end).</td><td><code>0.2</code></td></tr><tr><td><strong>End</strong></td><td>The gradient end position relative to the bounding box (0 = BB start, 1 = BB end).</td><td><code>0.8</code></td></tr></tbody></table><p><img src="'+S+'" alt="Gradient example"></p><h5 id="differences-in-interpolation-by-color-space" tabindex="-1">Differences in Interpolation by Color Space <a class="header-anchor" href="#differences-in-interpolation-by-color-space" aria-label="Permalink to &quot;Differences in Interpolation by Color Space&quot;">​</a></h5><p>Even with the same two colors (start color <code>#0000FF</code> = blue, end color <code>#FFFF00</code> = yellow), the appearance of the intermediate colors differs greatly depending on the chosen Color Space. <code>Okhsv</code> / <code>Okhsl</code> travel along the hue wheel through vivid intermediate colors (cyan to green), <code>Oklab</code> keeps perceptually uniform lightness, and <code>Linear RGB</code> produces a muddy gray midpoint due to simple numeric interpolation.</p><table tabindex="0"><thead><tr><th>Color Space</th><th>Sample</th></tr></thead><tbody><tr><td><strong>Okhsv</strong></td><td><img src="'+h+'" alt="Okhsv"></td></tr><tr><td><strong>Okhsl</strong></td><td><img src="'+c+'" alt="Okhsl"></td></tr><tr><td><strong>Oklab</strong></td><td><img src="'+g+'" alt="Oklab"></td></tr><tr><td><strong>Linear RGB</strong></td><td><img src="'+p+'" alt="Linear RGB"></td></tr></tbody></table><p><a id="gradient-crayon"></a></p><h5 id="crayon-hand-scribbled-fill" tabindex="-1">Crayon (Hand-Scribbled Fill) <a class="header-anchor" href="#crayon-hand-scribbled-fill" aria-label="Permalink to &quot;Crayon (Hand-Scribbled Fill)&quot;">​</a></h5><p>When Color Space is set to <code>Crayon</code>, instead of applying a gradient, hand-drawn scribble strokes in the <strong>Gradient End Color</strong> are drawn over the normal fill (Font Color). This creates a texture that looks like the text was roughly colored in with a crayon or colored pencil.</p><p>In this mode, the gradient parameters are reinterpreted as follows:</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Meaning in Crayon mode</th></tr></thead><tbody><tr><td><strong>Gradient End Color</strong></td><td>Color of the scribble strokes</td></tr><tr><td><strong>Angle</strong></td><td>Stroke direction</td></tr><tr><td><strong>Midpoint</strong></td><td>Spacing between strokes</td></tr><tr><td><strong>Start</strong></td><td>Stroke thickness</td></tr><tr><td><strong>End</strong></td><td>Stroke wobble (waviness) strength</td></tr></tbody></table><p><img src="'+T+'" alt="Crayon mode example"></p><h2 id="outline-stroke" tabindex="-1">Outline (Stroke) <a class="header-anchor" href="#outline-stroke" aria-label="Permalink to &quot;Outline (Stroke)&quot;">​</a></h2><p>Renders the outline (stroke) of the text glyphs. Useful when you want to keep text legible over busy backgrounds, or to give characters a bold, outlined look.</p><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>To make the outline visible, first set <strong>Width</strong> to a value greater than <code>0.0</code>. The outline is not rendered while it remains at <code>0.0</code>.</p></div><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Width</strong></td><td>Specifies the thickness of the outline as a ratio to the font size (e.g., <code>0.05</code> is about 5% of the character height). It does not scale with transform or stretch scaling. Setting it to <code>0.0</code> disables outline rendering.</td><td><code>0.0</code></td></tr><tr><td><strong>Gap</strong></td><td>Specifies the width of the gap between the fill and the outline (stroke) as a ratio to the font size. When set greater than <code>0.0</code>, the area between the text body and the outline is cut out, producing a three-layer &quot;detached outline&quot; look (body, gap, outline).</td><td><code>0.0</code></td></tr><tr><td><strong>Color</strong></td><td>Specifies the color of the outline (RGB + Opacity).</td><td>Off-black (<code>#1c1c1e</code>)</td></tr><tr><td><strong>Order</strong></td><td>Specifies the draw order of the stroke and fill. <code>Fill Over Stroke</code> draws the fill on top of the stroke, so only the outer half of the stroke is visible, creating an outside-stroke effect. <code>Stroke Over Fill</code> draws the stroke on top of the fill, causing it to overlap the glyph and appear to bite inward.</td><td><code>Fill Over Stroke</code></td></tr><tr><td><strong>Join Style</strong></td><td>Specifies the join style for the corners of the stroke.<br>・<strong>Miter Clip</strong>: Miter join. Sharpens corners, but clips (flattens) them if the miter length exceeds the miter limit.<br>・<strong>Round</strong>: Rounds corners.<br>・<strong>Bevel</strong>: Flattens corners (beveling).<br>・<strong>Miter Round</strong>: Miter join, but rounds corners if the limit is exceeded.<br>・<strong>Miter Bevel</strong>: Miter join, but bevels corners if the limit is exceeded.</td><td><code>Miter Clip</code></td></tr><tr><td><strong>Miter Limit</strong></td><td>The limit value for corner sharpness in miter joins. Sharper angles result in longer miter lengths. If the length exceeds this limit, the fallback treatment specified in Join Style (clip, round, bevel, etc.) is applied.</td><td><code>4.0</code></td></tr></tbody></table><h5 id="join-style-samples" tabindex="-1">Join Style Samples <a class="header-anchor" href="#join-style-samples" aria-label="Permalink to &quot;Join Style Samples&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Join Style</th><th>Sample</th></tr></thead><tbody><tr><td><strong>Miter</strong></td><td><img src="'+i+'" alt="Miter"></td></tr><tr><td><strong>Round</strong></td><td><img src="'+d+'" alt="Round"></td></tr><tr><td><strong>Bevel</strong></td><td><img src="'+s+'" alt="Bevel"></td></tr></tbody></table><h5 id="draw-order-order-samples" tabindex="-1">Draw Order (Order) Samples <a class="header-anchor" href="#draw-order-order-samples" aria-label="Permalink to &quot;Draw Order (Order) Samples&quot;">​</a></h5><table tabindex="0"><thead><tr><th>Draw Order</th><th>Sample</th></tr></thead><tbody><tr><td><strong>Fill Over Stroke</strong></td><td><img src="'+u+'" alt="Fill Over Stroke"></td></tr><tr><td><strong>Stroke Over Fill</strong></td><td><img src="'+l+'" alt="Stroke Over Fill"></td></tr></tbody></table><h2 id="shadow-settings" tabindex="-1">Shadow Settings <a class="header-anchor" href="#shadow-settings" aria-label="Permalink to &quot;Shadow Settings&quot;">​</a></h2><p>Renders a drop shadow for the entire text. Useful when you want to make the text stand out from the background with a sense of depth, or to improve legibility.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Draw Global Shadow</strong></td><td>Enables the global drop shadow that renders a shadow for all characters. When turned ON, the following parameters appear.<br>※ A character with an individual shadow color (Use Indiv Shadow Color) set on the Character Settings page casts a shadow even when this global shadow is OFF.</td><td>OFF</td></tr><tr><td><strong>Distance</strong></td><td>Specifies the shadow offset distance as a percentage of the canvas shorter side (whichever of width/height is smaller).</td><td><code>1.0</code></td></tr><tr><td><strong>Angle</strong></td><td>Specifies the shadow direction in degrees. 0° is right, 90° is downward.</td><td><code>45°</code></td></tr><tr><td><strong>Color</strong></td><td>Specifies the shadow color (RGB + Opacity).</td><td>Blue (<code>#5555ff</code>, opaque)</td></tr></tbody></table><p><img src="'+b+'" alt="Shadow example"></p><h2 id="bounding-box-settings" tabindex="-1">Bounding Box Settings <a class="header-anchor" href="#bounding-box-settings" aria-label="Permalink to &quot;Bounding Box Settings&quot;">​</a></h2><p>Configures rendering and filling of the bounding box (background frame) surrounding the entire text. Useful when you want to add a backing bar behind subtitles, or frame the text to give it a lower-third / telop look.</p><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>The <strong>bounding box (BB)</strong> is the smallest rectangle that encloses all characters and parts. When you move characters or parts individually, the size and position of the BB updates accordingly.</p></div><table tabindex="0"><thead><tr><th>Parameter</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><strong>Draw Bounding Box</strong></td><td>Enables drawing of the bounding box background and borders. When turned ON, the following parameters appear.</td><td>OFF</td></tr><tr><td><strong>Top Edge / Bottom Edge / Left Edge / Right Edge</strong></td><td>Specifies whether to draw the top, bottom, left, and right edges individually.</td><td>ON (all edges)</td></tr><tr><td><strong>Border Width</strong></td><td>Specifies the border width as a percentage of the font size.</td><td><code>20.0</code></td></tr><tr><td><strong>Border Color</strong></td><td>Specifies the border color.</td><td>Red (<code>1, 0, 0, 1</code>)</td></tr><tr><td><strong>Fill Background</strong></td><td>Specifies whether to fill the inside of the box with the background color. When ON, the background is rendered behind the glyphs.</td><td>OFF</td></tr><tr><td><strong>Fill Color</strong></td><td>Specifies the background fill color (RGB).</td><td>Light Purple (<code>1, 0.667, 1, 1</code>)</td></tr><tr><td><strong>Fill Opacity</strong></td><td>Specifies the opacity of the background fill (0.0 = completely transparent, 1.0 = completely opaque).</td><td><code>1.0</code></td></tr><tr><td><strong>Start Cap Style / End Cap Style</strong></td><td>Specifies the end cap style of the stroke when drawing open paths (e.g., L-shape with 3 or fewer edges). Options: <code>Butt</code> (flat), <code>Square</code> (square), <code>Round</code> (round), <code>Round Rev</code> (reversed round), <code>Triangle</code> (triangle), <code>Triangle Rev</code> (reversed triangle).</td><td><code>Butt</code></td></tr><tr><td><strong>Margin X / Margin Y</strong></td><td>Specifies the margin on the sides (X) and top/bottom (Y) as a percentage of the font size. Negative values can be used to draw the border inside the text boundary.</td><td><code>40.0</code></td></tr><tr><td><strong>Corner Radius</strong></td><td>Specifies the radius for rounding the bounding box corners as a percentage of the font size. <strong>This only takes effect when all of the Top / Bottom / Left / Right edges are turned ON</strong> (it is ignored if any edge is OFF).</td><td><code>0.0</code></td></tr><tr><td><strong>Border Offset</strong></td><td>Offsets the border rectangle in the X / Y directions, as a percentage of the font size. The fill rectangle stays in place, letting you shift only the border for offset frame designs.</td><td><code>0.0, 0.0</code></td></tr><tr><td><strong>Fill Offset</strong></td><td>Offsets the background fill rectangle in the X / Y directions, as a percentage of the font size. The border stays in place, letting you shift only the background.</td><td><code>0.0, 0.0</code></td></tr></tbody></table><p><img src="'+m+'" alt="Bounding box example (all edges, fill, and corner radius enabled)"></p><hr>',64))])}const D=f(O,[["render",_]]);export{G as __pageData,D as default};
